protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing documents and direct SQL queries reference "Discriminator", so preserve it.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the id property.
        // Existing documents have ids in format "Product|123", so preserve that format.
        entity.HasRootDiscriminatorInJsonId(true);

        // EF Core 9 Cosmos: HasIndex now throws at startup.
        // Manage indexing via the Cosmos DB indexing policy (Azure Portal / Bicep / Terraform).
        // Removed: entity.HasIndex(p => p.Sku);
    });
}

