        // EF Core 9 Cosmos: sync methods (ToList, SaveChanges, etc.) now throw.
        // Use async equivalents (ToListAsync, SaveChangesAsync).
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

